// Select URL v3 — JSON round-trip to bypass n8n Proxy sandbox
// item.json in n8n is a Proxy object where direct property access for Cyrillic keys
// returns undefined. JSON.parse(JSON.stringify(item.json)) creates a plain JS object.
const inputItems = $input.all();

// Ordered list of URL field names to check (priority order)
const URL_FIELD_PRIORITY = [
  'Веб-сайт', 'Веб-сайт 1', 'Веб-сайт 2', 'Веб-сайт 3',
  'Сайт', 'Сайт 1', 'Сайт 2', 'Сайт 3',
  'Website', 'Website 1', 'Website 2', 'Website 3',
  'Site', 'Site 1', 'Site 2', 'Site 3',
  'URL', 'Url', 'url', 'Домен', 'Domain', 'Главная страница', 'Homepage',
  'ВКонтакте', 'Вконтакте', 'VK', 'vk', 'VK URL',
  'Telegram 1', 'Telegram 2', 'Telegram 3', 'Telegram', 'telegram', 'Телеграм',
  '2GIS URL', '2ГИС',
];

// Hosts that should never be seeded
const BLOCKED_SEED = /^(www\.)?(wa\.me|whatsapp\.com|api\.whatsapp\.com|chat\.whatsapp\.com|viber\.com|viber\.click|max\.ru|max\.me|youtu\.be|youtube\.com|twitter\.com|x\.com|tiktok\.com|pinterest\.com|threads\.net)$/i;

// Social hosts — crawl differently
const VK_HOST = /^(www\.|m\.)?vk\.(com|ru)$/i;
const TG_HOST = /^(www\.)?(t\.me|telegram\.me|telegram\.org)$/i;
const SOCIAL_HOST = /^(www\.|m\.)?(vk\.com|vk\.ru|t\.me|telegram\.me|telegram\.org|facebook\.com|instagram\.com|linkedin\.com|twitter\.com|x\.com|youtube\.com|tiktok\.com|ok\.ru)$/i;

// Deep contact pages to crawl on regular websites
const DEEP_PATHS = [
  '/contacts', '/contact', '/kontakty',
  '/o-nas', '/o-kompanii', '/about', '/about-us', '/contact-us',
  '/info', '/feedback',
];

const MAX_CRAWL = 8;

function fixUrl(raw) {
  const s = String(raw == null ? '' : raw).replace(/[\u0000-\u001f]/g, '').trim();
  if (!s) return '';
  // Skip phone numbers, pure numbers, emails
  if (/^[+\d\s().\-]{5,}$/.test(s)) return '';
  if (/^[a-z0-9._%+\-]+@/i.test(s)) return '';
  const withScheme = /^https?:\/\//i.test(s) ? s : 'https://' + s.replace(/^\/+/, '');
  try {
    const p = new URL(withScheme);
    const h = p.hostname;
    if (!h || !h.includes('.') || h.length < 4) return '';
    if (!/[a-z]/i.test(h)) return '';
    if (p.username || p.password) return '';
    if (BLOCKED_SEED.test(h)) return '';
    p.hash = '';
    return p.toString();
  } catch { return ''; }
}

function canonKey(url) {
  try {
    const p = new URL(url);
    const host = p.hostname.toLowerCase().replace(/^www\./, '');
    const path = p.pathname.replace(/\/+$/, '') || '/';
    return host + path + (p.search || '');
  } catch { return url.toLowerCase(); }
}

function getHost(url) {
  try { return new URL(url).hostname.toLowerCase().replace(/^www\./, ''); } catch { return ''; }
}

// Extract all candidate URLs from a single field value
function extractFromValue(val) {
  const s = String(val == null ? '' : val).trim();
  if (!s) return [];
  const found = [];
  const seen = new Set();
  const add = (u) => {
    const fixed = fixUrl(u);
    if (fixed) { const k = canonKey(fixed); if (!seen.has(k)) { seen.add(k); found.push(fixed); } }
  };
  // Direct https?:// matches
  const direct = s.match(/https?:\/\/[^\s"'<>]+/gi) || [];
  direct.forEach(add);
  // Domain-like patterns
  const domains = s.match(/(?:[a-z0-9\-]+\.)+[a-z]{2,}(?:\/[^\s"'<>]*)?/gi) || [];
  domains.forEach(add);
  // Split by common separators and try each part
  s.split(/[,;|\n]+/).forEach(part => add(part.trim()));
  return found;
}

const outputItems = [];

for (let sourceIndex = 0; sourceIndex < inputItems.length; sourceIndex++) {
  try {
    const item = inputItems[sourceIndex];
    // JSON round-trip: creates a plain JS object, bypassing n8n's Proxy sandbox.
    // Without this, Cyrillic property keys are inaccessible (get/ownKeys traps broken).
    let row;
    try {
      const serialized = JSON.stringify(item.json || {});
      row = JSON.parse(serialized);
    } catch {
      row = {};
    }
    // Debug: log keys and website field for first item in batch
    if (sourceIndex === 0) {
      const allK = Object.keys(row);
      console.log('[SelectURL v3] batch size=' + inputItems.length + ' first_row keys=' + JSON.stringify(allK.slice(0, 15)));
      console.log('[SelectURL v3] website_field=' + JSON.stringify(row['\u0412\u0435\u0431-\u0441\u0430\u0439\u0442']) + ' vk=' + JSON.stringify(row['\u0412\u041a\u043e\u043d\u0442\u0430\u043a\u0442\u0435']) + ' tg=' + JSON.stringify(row['Telegram 1']));
    }
    const rowNumber = row.row_number;
    const stableKey = (rowNumber !== null && rowNumber !== undefined && String(rowNumber).trim() !== '')
      ? String(rowNumber).trim()
      : String(sourceIndex);

    // --- Find seed URLs using direct bracket access (not hasOwnProperty) ---
    const seedCandidates = [];
    const seenSeeds = new Set();

    const addSeed = (url, tag) => {
      if (seedCandidates.length >= 3) return;
      const k = canonKey(url);
      if (!k || seenSeeds.has(k)) return;
      seenSeeds.add(k);
      seedCandidates.push({ url, tag });
    };

    // Pass 1: check known URL fields via direct bracket access
    for (let fi = 0; fi < URL_FIELD_PRIORITY.length; fi++) {
      if (seedCandidates.length >= 3) break;
      const fieldName = URL_FIELD_PRIORITY[fi];
      const fieldVal = row[fieldName]; // direct access — works on Proxy objects too
      if (fieldVal == null || fieldVal === '') continue;
      const urls = extractFromValue(fieldVal);
      for (let ui = 0; ui < urls.length && seedCandidates.length < 3; ui++) {
        addSeed(urls[ui], 'field:' + fieldName);
      }
    }

    // Pass 2: scan ALL field values (any key) for URL-like content
    if (seedCandidates.length < 3) {
      const allKeys = Object.keys(row);
      for (let ki = 0; ki < allKeys.length && seedCandidates.length < 3; ki++) {
        const v = row[allKeys[ki]];
        if (v == null || v === '') continue;
        const urls = extractFromValue(v);
        for (let ui = 0; ui < urls.length && seedCandidates.length < 3; ui++) {
          addSeed(urls[ui], 'scan:' + allKeys[ki]);
        }
      }
    }

    console.log('[SelectURL] row=' + stableKey + ' seeds=' + seedCandidates.length + ' ' + seedCandidates.map(s => s.url).join(' | '));

    if (seedCandidates.length === 0) {
      outputItems.push({
        json: {
          ...row,
          targetUrl: '', targetHost: '', targetIsSocial: false,
          seed_url: '', seed_source: 'none', crawl_depth: 0, url_source: 'none',
          url_detected: false, source_row_index: sourceIndex,
          source_row_stable_key: stableKey, source_row_number: rowNumber ?? '',
          source_url_rank: 1, source_urls_count: 0,
        },
        pairedItem: { item: sourceIndex },
      });
      continue;
    }

    // Build crawl list from seeds
    const crawlList = [];
    const seenCrawl = new Set();

    const addCrawl = (url, depth, source, seedUrl, seedTag) => {
      if (crawlList.length >= MAX_CRAWL) return;
      const k = canonKey(url);
      if (!k || seenCrawl.has(k)) return;
      seenCrawl.add(k);
      const host = getHost(url);
      crawlList.push({
        url, depth, source, seedUrl, seedTag,
        targetHost: host,
        targetIsSocial: SOCIAL_HOST.test(host),
      });
    };

    for (let si = 0; si < seedCandidates.length; si++) {
      const seed = seedCandidates[si];
      addCrawl(seed.url, 0, seed.tag, seed.url, seed.tag);
      const host = getHost(seed.url);
      if (VK_HOST.test(host)) {
        try {
          const slug = new URL(seed.url).pathname.replace(/^\/+|\/+$/, '');
          if (slug) addCrawl('https://m.vk.com/' + slug, 1, 'vk-mobile', seed.url, seed.tag);
        } catch {}
      } else if (TG_HOST.test(host)) {
        try {
          const slug = new URL(seed.url).pathname.replace(/^\/+|\/+$/, '').split('/')[0];
          if (slug && slug !== 's' && !slug.startsWith('+') && !slug.startsWith('joinchat')) {
            addCrawl('https://t.me/s/' + slug, 1, 'tg-preview', seed.url, seed.tag);
          }
        } catch {}
      } else {
        try {
          const origin = new URL(seed.url).origin;
          for (let pi = 0; pi < DEEP_PATHS.length && crawlList.length < MAX_CRAWL; pi++) {
            const deep = fixUrl(origin + DEEP_PATHS[pi]);
            if (deep) addCrawl(deep, 1, 'deep:' + DEEP_PATHS[pi], seed.url, seed.tag);
          }
        } catch {}
      }
    }

    for (let ci = 0; ci < crawlList.length; ci++) {
      const entry = crawlList[ci];
      outputItems.push({
        json: {
          ...row,
          targetUrl: entry.url,
          targetHost: entry.targetHost,
          targetIsSocial: entry.targetIsSocial,
          seed_url: entry.seedUrl,
          seed_source: entry.seedTag,
          crawl_depth: entry.depth,
          url_source: entry.source,
          url_detected: true,
          source_row_index: sourceIndex,
          source_row_stable_key: stableKey,
          source_row_number: rowNumber ?? '',
          source_url_rank: ci + 1,
          source_urls_count: crawlList.length,
        },
        pairedItem: { item: sourceIndex },
      });
    }

  } catch (err) {
    const row = (inputItems[sourceIndex] && inputItems[sourceIndex].json) || {};
    const stableKey = (row.row_number != null && String(row.row_number).trim() !== '')
      ? String(row.row_number).trim() : String(sourceIndex);
    outputItems.push({
      json: {
        ...row,
        targetUrl: '', targetHost: '', targetIsSocial: false,
        seed_url: '', seed_source: 'select-url-error', crawl_depth: 0, url_source: 'error',
        url_detected: false, source_row_index: sourceIndex,
        source_row_stable_key: stableKey, source_row_number: (row.row_number ?? ''),
        source_url_rank: 1, source_urls_count: 0,
        select_url_error: String((err && err.message) || err),
      },
      pairedItem: { item: sourceIndex },
    });
  }
}

return outputItems;

const items = $input.all();
return items.map((item, idx) => {
  try {
    const j = item.json || {};
    const out = { ...j };
    if (out.html && typeof out.html === 'object') {
      if (typeof out.html.body === 'string') {
        out.statusCode = out.html.statusCode ?? out.statusCode ?? 0;
        out.html = out.html.body;
      } else {
        try { out.html = JSON.stringify(out.html); } catch { out.html = String(out.html); }
      }
    }
    if (typeof out.html !== 'string') out.html = out.html == null ? '' : String(out.html);
    if (!out.statusCode && j.body && typeof j.body === 'string' && !out.html) out.html = j.body;
    return { json: out, pairedItem: item.pairedItem ?? { item: idx } };
  } catch (err) {
    return { json: { ...(item.json || {}), html: '', normalize_error: String((err && err.message) || err) }, pairedItem: item.pairedItem ?? { item: idx } };
  }
});

const inputItems = $input.all();

const emailRegex = /[a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;
const emailValidationRegex = /^[a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})$/iu;
const mailtoRegex = /mailto:([^\s"'<>]+)/gi;

const obfuscatedEmailRegexEn =
  /([a-z0-9._%+-]+)\s*(?:\[at\]|\(at\)|\{at\}|\sat\s|\{@\}|＠)\s*([a-z0-9а-яё.-]+)\s*(?:\[dot\]|\(dot\)|\{dot\}|\sdot\s|\{\.\}|．)\s*([a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;

const obfuscatedEmailRegexRu =
  /([a-z0-9._%+-]+)\s*(?:\[собака\]|\(собака\)|\{собака\}|\sсобака\s|\[собачка\]|\(собачка\)|\sсобачка\s|\[at\]|\(at\)|\sat\s)\s*([a-z0-9а-яё.-]+)\s*(?:\[точка\]|\(точка\)|\{точка\}|\sточка\s|\[dot\]|\(dot\)|\sdot\s)\s*([a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;

const ruLabelRegex = /(?:почта|электронная\s*почта|e-?mail|пишите\s+на)\s*[:\-–]?\s*([a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58}))/giu;
const dataAttrRegex = /\bdata-(?:e-?mail|mail)\s*=\s*["']([^"']+)["']/giu;
const itempropEmailRegex = /<[^>]*\bitemprop\s*=\s*["']email["'][^>]*>([\s\S]{0,300}?)<\/[^>]+>|\bitemprop\s*=\s*["']email["'][^>]*\bcontent\s*=\s*["']([^"']+)["']/giu;
const cfEncodedRegex = /data-cfemail\s*=\s*["']([a-f0-9]{4,})["']/gi;
const cfemailHrefRegex = /\/cdn-cgi\/l\/email-protection#([a-f0-9]{4,})/gi;

const blockedLocalPatterns = [
  /^example/i, /^test/i, /^noreply/i, /^no-reply/i, /^donotreply/i,
  /^mailer-daemon$/i, /^postmaster$/i, /^abuse$/i, /^webmaster$/i,
  /^[a-f0-9]{16,}$/i, /^[a-z0-9]{20,}$/i,
];

const blockedDomains = [
  'wixpress.com', 'wix.com', 'parastorage.com', 'sentry.io', 'sentry-cdn.com',
  'cloudflare.com', 'cloudfront.net', 'google.com', 'google.ru', 'googleapis.com',
  'googleusercontent.com', 'gstatic.com', 'googletagmanager.com', 'google-analytics.com',
  'doubleclick.net', 'googlesyndication.com', 'yandex.net', 'duckduckgo.com', 'bing.com',
  'example.com', 'example.org', 'example.net', 'example.ru', 'domain.com', 'domain.ru',
  'site.ru', 'mail.com', 'jsdelivr.net', 'unpkg.com', 'jquery.com', 'cdnjs.cloudflare.com',
  'w3.org', 'schema.org', 'ogp.me', 'fbcdn.net', 'ytimg.com', 'vkuser.net',
  'segment.io', 'segment.com', 'amplitude.com', 'mixpanel.com', 'hotjar.com', 'newrelic.com',
  'tildacdn.com', 'tildacdn.info',
];

const decodeHtmlEntitiesLite = (text) =>
  String(text || '')
    .replace(/&amp;/gi, '&').replace(/&quot;/gi, '"').replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<').replace(/&gt;/gi, '>')
    .replace(/&#x([0-9a-f]+);/gi, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#(\d+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)));

const decodeCfEmail = (hexString) => {
  try {
    if (!hexString || hexString.length < 4 || hexString.length % 2 !== 0) return '';
    const key = parseInt(hexString.slice(0, 2), 16);
    let decoded = '';
    for (let i = 2; i < hexString.length; i += 2) {
      decoded += String.fromCharCode(parseInt(hexString.slice(i, i + 2), 16) ^ key);
    }
    return decoded;
  } catch { return ''; }
};

const normalizeEmail = (value) => {
  if (!value) return '';
  let email = String(value).trim();
  email = decodeHtmlEntitiesLite(email);
  email = email
    .replace(/^mailto:/i, '')
    .replace(/^['"\s<>()\[\]{}]+|['"\s<>()\[\]{}.,;:!]+$/g, '')
    .replace(/\u200b|\u200c|\u200d|\ufeff/g, '')
    .toLowerCase();
  if (!/@/.test(email) || /\s/.test(email) || email.length > 254) return '';
  if (!emailValidationRegex.test(email)) return '';
  return email;
};

const isBlocked = (email) => {
  if (!email) return true;
  const parts = email.split('@');
  if (parts.length !== 2) return true;
  const local = parts[0] || '';
  const domain = (parts[1] || '').toLowerCase();
  if (blockedLocalPatterns.some((rx) => rx.test(local))) return true;
  if (blockedDomains.some((d) => domain === d || domain.endsWith('.' + d))) return true;
  return false;
};

const collectByRegex = (text, regex, mapFn) => {
  const found = [];
  for (const m of String(text || '').matchAll(regex)) {
    const candidate = mapFn(m);
    if (!candidate) continue;
    const email = normalizeEmail(candidate);
    if (email && !isBlocked(email)) found.push(email);
  }
  return found;
};

const extractFromJsonLikeScripts = (html) => {
  const found = new Set();
  const scriptRegex = /<script\b([^>]*)>([\s\S]*?)<\/script>/gi;
  const stateMarkerRegex = /__NEXT_DATA__|__INITIAL_STATE__|__NUXT__|__APOLLO_STATE__|__REDUX_STATE__|__PRELOADED_STATE__|__SERVER_STATE__/i;
  const walk = (node) => {
    if (!node) return;
    if (typeof node === 'string') {
      const emails = node.match(emailRegex) || [];
      for (const e of emails) { const n = normalizeEmail(e); if (n && !isBlocked(n)) found.add(n); }
      emailRegex.lastIndex = 0;
      return;
    }
    if (Array.isArray(node)) return node.forEach(walk);
    if (typeof node === 'object') return Object.values(node).forEach(walk);
  };
  for (const m of String(html || '').matchAll(scriptRegex)) {
    const attrs = String(m[1] || '');
    const scriptBody = String(m[2] || '').trim();
    if (!scriptBody) continue;
    const hasMarker = stateMarkerRegex.test(attrs) || stateMarkerRegex.test(scriptBody);
    if (!hasMarker) continue;
    const candidates = [scriptBody];
    const assignMatch = scriptBody.match(/(?:window\.)?__(?:NUXT__|INITIAL_STATE__|APOLLO_STATE__|REDUX_STATE__|PRELOADED_STATE__|SERVER_STATE__)\s*=\s*([\s\S]*?);?\s*$/i);
    if (assignMatch && assignMatch[1]) candidates.push(assignMatch[1].trim());
    let parsed = false;
    for (const candidate of candidates) {
      try { walk(JSON.parse(candidate)); parsed = true; break; } catch {}
    }
    if (parsed) continue;
    const inline = scriptBody.match(emailRegex) || [];
    for (const e of inline) { const n = normalizeEmail(e); if (n && !isBlocked(n)) found.add(n); }
    emailRegex.lastIndex = 0;
  }
  return Array.from(found);
};

const extractEmailsFromText = (text) => {
  const found = new Set();
  const raw = String(text || '');
  const decodedEntity = decodeHtmlEntitiesLite(raw);
  let decodedUri = decodedEntity;
  try { decodedUri = decodeURIComponent(decodedEntity); } catch {}
  const variants = [raw, decodedEntity, decodedUri];
  for (const variant of variants) {
    for (const m of variant.match(emailRegex) || []) {
      const n = normalizeEmail(m);
      if (n && !isBlocked(n)) found.add(n);
    }
    emailRegex.lastIndex = 0;
    for (const m of variant.matchAll(mailtoRegex)) {
      const n = normalizeEmail((m[1] || '').split('?')[0]);
      if (n && !isBlocked(n)) found.add(n);
    }
    for (const m of variant.matchAll(obfuscatedEmailRegexEn)) {
      const n = normalizeEmail(`${m[1] || ''}@${m[2] || ''}.${m[3] || ''}`);
      if (n && !isBlocked(n)) found.add(n);
    }
    for (const m of variant.matchAll(obfuscatedEmailRegexRu)) {
      const n = normalizeEmail(`${m[1] || ''}@${m[2] || ''}.${m[3] || ''}`);
      if (n && !isBlocked(n)) found.add(n);
    }
    for (const m of variant.matchAll(ruLabelRegex)) {
      const n = normalizeEmail(m[1] || '');
      if (n && !isBlocked(n)) found.add(n);
    }
    for (const e of collectByRegex(variant, dataAttrRegex, (m) => m[1])) found.add(e);
    for (const e of collectByRegex(variant, itempropEmailRegex, (m) => m[1] || m[2])) found.add(e);
    for (const m of variant.matchAll(cfEncodedRegex)) {
      const d = decodeCfEmail(m[1] || ''); const n = normalizeEmail(d);
      if (n && !isBlocked(n)) found.add(n);
    }
    for (const m of variant.matchAll(cfemailHrefRegex)) {
      const d = decodeCfEmail(m[1] || ''); const n = normalizeEmail(d);
      if (n && !isBlocked(n)) found.add(n);
    }
  }
  return Array.from(found);
};

const extractFromJsonLd = (html) => {
  const found = new Set();
  const blockRegex = /<script\b[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
  const walk = (node) => {
    if (!node) return;
    if (typeof node === 'string') {
      const matches = node.match(emailRegex) || [];
      for (const m of matches) { const n = normalizeEmail(m); if (n && !isBlocked(n)) found.add(n); }
      emailRegex.lastIndex = 0; return;
    }
    if (Array.isArray(node)) return node.forEach(walk);
    if (typeof node === 'object') return Object.values(node).forEach(walk);
  };
  for (const match of String(html || '').matchAll(blockRegex)) {
    const jsonText = String(match[1] || '').trim();
    if (!jsonText) continue;
    try { walk(JSON.parse(jsonText)); } catch {
      const inner = jsonText.match(emailRegex) || [];
      for (const e of inner) { const n = normalizeEmail(e); if (n && !isBlocked(n)) found.add(n); }
      emailRegex.lastIndex = 0;
    }
  }
  return Array.from(found);
};

const rankEmails = (emails, domainsHint) => {
  const hints = new Set((domainsHint || []).map((d) => String(d || '').toLowerCase().replace(/^www\./, '')).filter(Boolean));
  const preferredLocals = /^(info|contact|hello|support|sales|office|mail|admin)$/i;
  const noisyLocals = /^(noreply|no-reply|donotreply|mailer-daemon|example|test)$/i;
  const score = (email) => {
    const [local, domainRaw] = String(email || '').toLowerCase().split('@');
    const domain = (domainRaw || '').replace(/^www\./, '');
    let s = 0;
    if (hints.has(domain)) s += 120;
    for (const hint of hints) {
      if (domain.endsWith('.' + hint) || hint.endsWith('.' + domain)) { s += 100; break; }
    }
    if (preferredLocals.test(local || '')) s += 40;
    if ((local || '').length <= 4) s += 5;
    if (/\d{3,}/.test(local || '')) s -= 12;
    if (noisyLocals.test(local || '')) s -= 80;
    return s;
  };
  return Array.from(new Set(emails || []))
    .map((email) => ({ email, score: score(email) }))
    .sort((a, b) => b.score - a.score || a.email.localeCompare(b.email))
    .map((x) => x.email);
};

const getDomainHints = (bucket) => {
  const hints = new Set();
  for (const url of bucket.fetchedUrls) {
    try {
      const host = new URL(url).hostname.replace(/^www\./i, '').toLowerCase();
      if (/catalog\.api\.2gis\./i.test(host)) continue;
      hints.add(host);
    } catch {}
  }
  const targetHost = String(bucket.mergedJson.targetHost || '').toLowerCase().replace(/^www\./, '');
  if (targetHost) hints.add(targetHost);
  return Array.from(hints);
};

const maxHtmlLength = 1500000;
// FIX: Key buckets by source_row_stable_key (row_number-based) to prevent
// cross-row email collisions when two rows share the same batch sourceIndex.
const buckets = new Map();

for (let idx = 0; idx < inputItems.length; idx++) {
  try {
    const item = inputItems[idx];
    const currentJson = item.json || {};
    // Prefer stable key (row_number string) set by Select URL node
    const stableKey = String(currentJson.source_row_stable_key ?? currentJson.source_row_index ?? idx);

    if (!buckets.has(stableKey)) {
      buckets.set(stableKey, {
        mergedJson: { ...currentJson },
        emailsSet: new Set(),
        fetchedUrls: new Set(),
        successUrls: new Set(),
        hasFetchError: false,
        maxStatusCode: 0,
        sortKey: Number(currentJson.source_row_number) || idx,
      });
    }

    const bucket = buckets.get(stableKey);
    bucket.mergedJson = { ...bucket.mergedJson, ...currentJson };

    let htmlRaw = String(currentJson.html ?? currentJson.body ?? currentJson.data ?? currentJson.response ?? '');
    if (htmlRaw.length > maxHtmlLength) htmlRaw = htmlRaw.slice(0, maxHtmlLength);

    const statusCode = Number(currentJson.statusCode || currentJson.status || 0);
    if (statusCode && statusCode > bucket.maxStatusCode) bucket.maxStatusCode = statusCode;

    const prepared = htmlRaw
      .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
      .replace(/<!--([\s\S]*?)-->/g, ' ');

    for (const e of extractEmailsFromText(prepared)) bucket.emailsSet.add(e);
    for (const e of extractFromJsonLd(htmlRaw)) bucket.emailsSet.add(e);
    for (const e of extractFromJsonLikeScripts(htmlRaw)) bucket.emailsSet.add(e);

    const fetchedUrl = String(currentJson.targetUrl || '').trim();
    if (fetchedUrl) {
      bucket.fetchedUrls.add(fetchedUrl);
      const isSuccess = htmlRaw.length > 0 && (!statusCode || statusCode < 400);
      if (isSuccess) bucket.successUrls.add(fetchedUrl);
    }

    if (currentJson.error || (statusCode && statusCode >= 400) || (!htmlRaw && fetchedUrl)) {
      bucket.hasFetchError = true;
    }
  } catch (err) {
    const fallbackJson = (inputItems[idx] && inputItems[idx].json) || {};
    const fallbackKey = String(fallbackJson.source_row_stable_key ?? fallbackJson.source_row_index ?? idx);
    if (!buckets.has(fallbackKey)) {
      buckets.set(fallbackKey, {
        mergedJson: { ...fallbackJson },
        emailsSet: new Set(),
        fetchedUrls: new Set(),
        successUrls: new Set(),
        hasFetchError: true,
        maxStatusCode: 0,
        sortKey: Number(fallbackJson.source_row_number) || idx,
      });
    }
    const bucket = buckets.get(fallbackKey);
    bucket.hasFetchError = true;
    bucket.mergedJson.extract_error = String((err && err.message) || err);
  }
}

const stableKeys = Array.from(buckets.keys()).sort((a, b) => {
  return (buckets.get(a).sortKey || 0) - (buckets.get(b).sortKey || 0);
});

return stableKeys.map((stableKey, outputIdx) => {
  const bucket = buckets.get(stableKey);
  const mergedJson = { ...bucket.mergedJson };
  const newEmails = Array.from(bucket.emailsSet);

  const existing1 = String(mergedJson['E-mail'] ?? mergedJson['E-mail 1'] ?? mergedJson['Email'] ?? '').trim().toLowerCase();
  const existing2 = String(mergedJson['E-mail 2'] ?? mergedJson['Email 2'] ?? '').trim().toLowerCase();
  const existing3 = String(mergedJson['E-mail 3'] ?? mergedJson[' E-mail 3'] ?? mergedJson['Email 3'] ?? '').trim().toLowerCase();

  const existingList = [existing1, existing2, existing3].filter(Boolean);
  const existingSet = new Set(existingList);

  const ranked = rankEmails([...existingList, ...newEmails], getDomainHints(bucket));
  const final1 = ranked[0] || '';
  const final2 = ranked[1] || '';
  const final3 = ranked[2] || '';

  const trulyNewEmails = ranked.filter((e) => !existingSet.has(e));

  mergedJson.source_row_stable_key = stableKey;
  mergedJson.parsed_urls = Array.from(bucket.fetchedUrls);
  mergedJson.parsed_urls_count = mergedJson.parsed_urls.length;
  mergedJson.success_urls_count = bucket.successUrls.size;
  mergedJson.max_status_code = bucket.maxStatusCode;
  mergedJson.emails_array = ranked;
  mergedJson.emails_string = ranked.join(', ');
  mergedJson.new_emails = trulyNewEmails;
  mergedJson.new_emails_count = trulyNewEmails.length;
  mergedJson.email_1 = final1;
  mergedJson.email_2 = final2;
  mergedJson.email_3 = final3;
  mergedJson.ID = mergedJson.ID ?? '';

  if (newEmails.length > 0) {
    mergedJson.parse_status = trulyNewEmails.length > 0 ? 'emails_found' : 'emails_unchanged';
  } else if (bucket.hasFetchError && bucket.successUrls.size === 0) {
    mergedJson.parse_status = 'fetch_error';
  } else if (bucket.fetchedUrls.size === 0) {
    mergedJson.parse_status = 'no_url';
  } else {
    mergedJson.parse_status = 'no_email_found';
  }

  delete mergedJson.html;
  delete mergedJson.body;
  delete mergedJson.data;
  delete mergedJson.response;
  delete mergedJson.headers;

  return { json: mergedJson, pairedItem: { item: outputIdx } };
});

