  if (stats[status] === undefined) stats.other++; else stats[status]++;
  if (sample.length < 5 && j.new_emails_count > 0) {
    sample.push({ row: j.row_number ?? j.source_row_number ?? '?', name: j['Наименование'] || j.name || '?', emails: j.new_emails || [] });
  }
}
console.log('[Astra] Batch progress:', JSON.stringify(stats));
if (sample.length) console.log('[Astra] Sample new emails:', JSON.stringify(sample));
return items;

